func (adoption0 *Adoption) AttachUser(ctx context.Context, exec bob.Executor, user1 *User) error {
	var err error

	_, err = attachAdoptionUser0(ctx, exec, 1, adoption0, user1)
	if err != nil {
		return err
	}

	adoption0.R.User = user1

	user1.R.Adoptions = append(user1.R.Adoptions, adoption0)

	return nil
}

