func (o *Adoption) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "Animal":
		rel, ok := retrieved.(*Animal)
		if !ok {
			return fmt.Errorf("adoption cannot load %T as %q", retrieved, name)
		}

		o.R.Animal = rel

		if rel != nil {
			rel.R.Adoptions = AdoptionSlice{o}
		}
		return nil
	case "Organization":
		rel, ok := retrieved.(*Organization)
		if !ok {
			return fmt.Errorf("adoption cannot load %T as %q", retrieved, name)
		}

		o.R.Organization = rel

		if rel != nil {
			rel.R.Adoptions = AdoptionSlice{o}
		}
		return nil
	case "User":
		rel, ok := retrieved.(*User)
		if !ok {
			return fmt.Errorf("adoption cannot load %T as %q", retrieved, name)
		}

		o.R.User = rel

		if rel != nil {
			rel.R.Adoptions = AdoptionSlice{o}
		}
		return nil
	default:
		return fmt.Errorf("adoption has no relationship %q", name)
	}
}

type adoptionPreloader struct {
	Animal       func(...psql.PreloadOption) psql.Preloader
	Organization func(...psql.PreloadOption) psql.Preloader
	User         func(...psql.PreloadOption) psql.Preloader
}

func buildAdoptionPreloader() adoptionPreloader {
	return adoptionPreloader{
		Animal: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Animal, AnimalSlice](psql.PreloadRel{
				Name: "Animal",
				Sides: []psql.PreloadSide{
					{
						From:        Adoptions,
						To:          Animals,
						FromColumns: []string{"animal_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, Animals.Columns.Names(), opts...)
		},
		Organization: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Organization, OrganizationSlice](psql.PreloadRel{
				Name: "Organization",
				Sides: []psql.PreloadSide{
					{
						From:        Adoptions,
						To:          Organizations,
						FromColumns: []string{"organization_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, Organizations.Columns.Names(), opts...)
		},
		User: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*User, UserSlice](psql.PreloadRel{
				Name: "User",
				Sides: []psql.PreloadSide{
					{
						From:        Adoptions,
						To:          Users,
						FromColumns: []string{"user_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, Users.Columns.Names(), opts...)
		},
	}
}

