// LoadAnimal loads the adoption's Animal into the .R struct
func (o *Adoption) LoadAnimal(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Animal = nil

	related, err := o.Animal(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.Adoptions = AdoptionSlice{o}

	o.R.Animal = related
	return nil
}

// LoadAnimal loads the adoption's Animal into the .R struct
func (os AdoptionSlice) LoadAnimal(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	animals, err := os.Animal(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range animals {
			if !o.AnimalID.IsValue() {
				continue
			}

			if !(o.AnimalID.IsValue() && o.AnimalID.MustGet() == rel.ID) {
				continue
			}

			rel.R.Adoptions = append(rel.R.Adoptions, o)

			o.R.Animal = rel
			break
		}
	}

	return nil
}

