type adoptionJoins[Q dialect.Joinable] struct {
	typ          string
	Animal       modAs[Q, animalColumns]
	Organization modAs[Q, organizationColumns]
	User         modAs[Q, userColumns]
}

func (j adoptionJoins[Q]) aliasedAs(alias string) adoptionJoins[Q] {
	return buildAdoptionJoins[Q](buildAdoptionColumns(alias), j.typ)
}

func buildAdoptionJoins[Q dialect.Joinable](cols adoptionColumns, typ string) adoptionJoins[Q] {
	return adoptionJoins[Q]{
		typ: typ,
		Animal: modAs[Q, animalColumns]{
			c: Animals.Columns,
			f: func(to animalColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Animals.Name().As(to.Alias())).On(
						to.ID.EQ(cols.AnimalID),
					))
				}

				return mods
			},
		},
		Organization: modAs[Q, organizationColumns]{
			c: Organizations.Columns,
			f: func(to organizationColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Organizations.Name().As(to.Alias())).On(
						to.ID.EQ(cols.OrganizationID),
					))
				}

				return mods
			},
		},
		User: modAs[Q, userColumns]{
			c: Users.Columns,
			f: func(to userColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Users.Name().As(to.Alias())).On(
						to.ID.EQ(cols.UserID),
					))
				}

				return mods
			},
		},
	}
}
